// O(1) Constant Time
function getFirst(arr) { return arr[0]; }

// O(N) Linear Time
function printAll(arr) {
  for (let item of arr) console.log(item);
}

// O(N^2) Quadratic Time
function printPairs(arr) {
  for (let i of arr)
    for (let j of arr) console.log(i, j);
}

